import React, { useState, useRef, useCallback } from "react";
import * as mammoth from "mammoth";


// ─── HELPERS ─────────────────────────────────────────────────────────────────
const COP = (n) => new Intl.NumberFormat("es-CO", { style: "currency", currency: "COP", maximumFractionDigits: 0 }).format(Number(n) || 0);
const toBase64 = (file) => new Promise((res, rej) => { const r = new FileReader(); r.onload = () => res(r.result.split(",")[1]); r.onerror = rej; r.readAsDataURL(file); });
const toDataURL = (file) => new Promise((res, rej) => { const r = new FileReader(); r.onload = () => res(r.result); r.onerror = rej; r.readAsDataURL(file); });
const toArrayBuffer = (file) => new Promise((res, rej) => { const r = new FileReader(); r.onload = () => res(r.result); r.onerror = rej; r.readAsArrayBuffer(file); });
const isImage = (f) => f.type.startsWith("image/");
const isPDF = (f) => f.type === "application/pdf";
const isText = (f) => ["text/plain","text/csv"].includes(f.type) || /\.(txt|csv|md)$/i.test(f.name);
const isOffice = (f) => /\.(xlsx|xls|pptx|ppt|docx|doc)$/i.test(f.name);
const isWord = (f) => /\.(docx|doc)$/i.test(f.name);
const MEDIA = { "image/png":"image/png","image/jpeg":"image/jpeg","image/jpg":"image/jpeg","image/webp":"image/webp","application/pdf":"application/pdf" };

// Extrae texto de archivos Word usando mammoth
const extractWordText = async (file) => {
  try {
    const arrayBuffer = await toArrayBuffer(file);
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value || "";
  } catch(e) {
    return "";
  }
};

