// ─── RECALC ───────────────────────────────────────────────────────────────────
const recalcOption = (opt, applyTax = true, applyFee = true, presupuesto = 0) => {
  // Recalcular servicio 10% automáticamente sobre A&B
  const abItems = opt.items.filter(i => {
    const cat = (i.categoria||i.concepto||"").toLowerCase();
    return cat.includes("catering") || cat.includes("alimento") || cat.includes("bebida") || 
           cat.includes("desayuno") || cat.includes("almuerzo") || cat.includes("cena") ||
           cat.includes("café") || cat.includes("coffee") || cat.includes("estación") ||
           cat.includes("menú") || cat.includes("buffet") || cat.includes("a&b") ||
           cat.includes("alimentos y bebidas");
  });
  const totalAB = abItems.reduce((s, i) => s + (Number(i.v_total) || 0), 0);

  // Actualizar ítem de servicio 10% si existe, o agregarlo si hay A&B
  const servicioIdx = opt.items.findIndex(i => 
    (i.concepto||"").toLowerCase().includes("servicio") && 
    ((i.concepto||"").includes("10%") || (i.concepto||"").toLowerCase().includes("service"))
  );
  if (totalAB > 0) {
    const servicioVal = Math.round(totalAB * 0.10 / 1000) * 1000;
    if (servicioIdx >= 0) {
      opt.items[servicioIdx].v_unitario = servicioVal;
      opt.items[servicioIdx].v_total = servicioVal;
      opt.items[servicioIdx].cantidad = 1;
    }
  }

  // Si hay presupuesto del cliente, ajustar precios para llegar al subtotal objetivo
  if (presupuesto > 0) {
    // El subtotal objetivo debe ser tal que subtotal llegue al presupuesto
    const subtotalObjetivo = presupuesto;
    const subtotalActual = opt.items.reduce((s, i) => s + (Number(i.v_total) || 0), 0);
    if (subtotalActual > 0) {
      const factor = subtotalObjetivo / subtotalActual;
      // Solo ajustar ítems que NO sean coordinación, servicio 10% o cortesía
      opt.items.forEach(item => {
        const concepto = (item.concepto||"").toLowerCase();
        const esInmutable = concepto.includes("coordinación") || concepto.includes("coordinacion") || 
                           concepto.includes("servicio 10") || concepto.includes("service charge");
        if (!esInmutable && item.v_total > 0) {
          item.v_unitario = Math.round((item.v_unitario * factor) / 1000) * 1000;
          item.v_total = Math.round(item.cantidad * item.v_unitario / 1000) * 1000;
        }
      });
      // Recalcular servicio 10% con los nuevos valores A&B
      const newTotalAB = opt.items.filter(i => {
        const cat = (i.categoria||i.concepto||"").toLowerCase();
        return cat.includes("catering") || cat.includes("alimento") || cat.includes("bebida") || 
               cat.includes("desayuno") || cat.includes("almuerzo") || cat.includes("cena") ||
               cat.includes("café") || cat.includes("coffee") || cat.includes("estación");
      }).reduce((s, i) => s + (Number(i.v_total) || 0), 0);
      if (newTotalAB > 0 && servicioIdx >= 0) {
        const nuevoServicio = Math.round(newTotalAB * 0.10 / 1000) * 1000;
        opt.items[servicioIdx].v_unitario = nuevoServicio;
        opt.items[servicioIdx].v_total = nuevoServicio;
      }
    }
  }

  const sub = opt.items.reduce((s, i) => s + (Number(i.v_total) || 0), 0);
  const fee = (applyTax && applyFee) ? Math.round(sub * 0.16 / 1000) * 1000 : 0;
  const conFee = sub + fee;
  const iva = applyTax ? Math.round(conFee * 0.19 / 1000) * 1000 : 0;
  opt.subtotal = sub; opt.fee = fee; opt.subtotal_con_fee = conFee; opt.iva = iva; opt.total = conFee + iva;
};

// ─── PROVIDER FILE ENTRY ──────────────────────────────────────────────────────
const PROVIDER_CATEGORIES = ["Catering / Alimentos","Bebidas","Audiovisual / Tecnología","Venue / Salón","Logística / Transporte","Personal / Staff","Decoración","Entretenimiento","Material POP","PR / Medios","Marketing Digital","General / Sin categoría"];

